var modelIntercept = 0.70881988398219709

type acNode struct {
	next map[rune]int
	fail int
	out  []int
}

type acAutomaton struct {
	nodes []acNode
}

func newACAutomaton(patterns []string) *acAutomaton {
	a := &acAutomaton{nodes: []acNode{{next: map[rune]int{}}}}

	for i, pattern := range patterns {
		state := 0
		for _, ch := range pattern {
			nextState, ok := a.nodes[state].next[ch]
			if !ok {
				nextState = len(a.nodes)
				a.nodes[state].next[ch] = nextState
				a.nodes = append(a.nodes, acNode{next: map[rune]int{}})
			}
			state = nextState
		}
		a.nodes[state].out = append(a.nodes[state].out, i)
	}

	queue := make([]int, 0)
	for _, nextState := range a.nodes[0].next {
		a.nodes[nextState].fail = 0
		queue = append(queue, nextState)
	}

	for len(queue) > 0 {
		state := queue[0]
		queue = queue[1:]

		for ch, nextState := range a.nodes[state].next {
			failState := a.nodes[state].fail
			for failState != 0 {
				if _, ok := a.nodes[failState].next[ch]; ok {
					break
				}
				failState = a.nodes[failState].fail
			}

			if to, ok := a.nodes[failState].next[ch]; ok {
				a.nodes[nextState].fail = to
			} else {
				a.nodes[nextState].fail = 0
			}

			f := a.nodes[nextState].fail
			if len(a.nodes[f].out) > 0 {
				a.nodes[nextState].out = append(a.nodes[nextState].out, a.nodes[f].out...)
			}

			queue = append(queue, nextState)
		}
	}

	return a
}

func (a *acAutomaton) findMatches(text string, seen []bool) {
	state := 0
	for _, ch := range text {
		for state != 0 {
			if _, ok := a.nodes[state].next[ch]; ok {
				break
			}
			state = a.nodes[state].fail
		}

		if to, ok := a.nodes[state].next[ch]; ok {
			state = to
		} else {
			state = 0
		}

		if len(a.nodes[state].out) > 0 {
			for _, id := range a.nodes[state].out {
				seen[id] = true
			}
		}
	}
}

func isWordRune(r rune) bool {
	return r == '_' || unicode.IsLetter(r) || unicode.IsDigit(r)
}

func tokenizeLowerWords(input string) []string {
	runes := []rune(strings.ToLower(input))
	out := make([]string, 0, len(runes)/4)
	start := -1

	flush := func(end int) {
		if start < 0 {
			return
		}
		if end-start >= 2 {
			out = append(out, string(runes[start:end]))
		}
		start = -1
	}

	for i, r := range runes {
		if isWordRune(r) {
			if start < 0 {
				start = i
			}
			continue
		}
		flush(i)
	}
	flush(len(runes))
	return out
}

func boundaryPatterns(tokens []string) []string {
	patterns := make([]string, len(tokens))
	for i, token := range tokens {
		patterns[i] = " " + token + " "
	}
	return patterns
}

var vectorizerAC = newACAutomaton(boundaryPatterns(modelTokens))

func DecisionScore(text string) float64 {
	tokens := tokenizeLowerWords(text)
	if len(tokens) == 0 {
		return modelIntercept
	}

	normalized := " " + strings.Join(tokens, " ") + " "
	seen := make([]bool, len(modelTokens))
	vectorizerAC.findMatches(normalized, seen)

	score := modelIntercept
	for i, ok := range seen {
		if ok {
			score += modelWeights[i]
		}
	}
	return score
}

func PredictLabel(text string) string {
	if DecisionScore(text) > 0 {
		return PositiveLabel
	}
	return NegativeLabel
}

func NeedsFactCheck(text string) bool {
	return PredictLabel(text) == "needs_fact_check"
}

func Predict(text string) (label string, needsFactCheck bool, score float64) {
	score = DecisionScore(text)
	if score > 0 {
		label = PositiveLabel
	} else {
		label = NegativeLabel
	}
	needsFactCheck = label == "needs_fact_check"
	return
}
